const basePriceFor = (type: string): number => BASE_PRICES[type] ?? 0;

const isComponentType = (type: string): boolean =>
  COMPONENT_TYPES.includes(type);

const itemModifiedPremium = (item: Item): number => {
  const base = basePriceFor(item.type);
  return item.cursed ? base * 1.5 : base;
};

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const group = groups.get(item.type) ?? [];
    group.push(item);
    groups.set(item.type, group);
  }
  return groups;
};

const premiumForGroup = (type: string, group: Item[]): number => {
  if (isComponentType(type) && group.length === BLOCK_SIZE) return BLOCK_PRICE;
  return group.reduce((sum, item) => sum + itemModifiedPremium(item), 0);
};

export const quote = (
  _customer: Customer,
  items: Item[],
  _previousQuoteCount: number,
): number => {
  let basePremium = 0;
  for (const [type, group] of groupByType(items)) {
    basePremium += premiumForGroup(type, group);
  }
  return basePremium + PROCESSING_FEE;
};

